const items = $input.all();

// 1. Pick a random row
const randomIndex = Math.floor(Math.random() * items.length);
const randomRow = items[randomIndex];

// 2. Access the simplified property directly
const keywordString = randomRow.json.property_main_kw;

// 3. Output the clean JSON
return [{
    json: {
        targetKeyword: keywordString
    }
}];

// 1. Explicitly grab the raw XML string from the 'Get Sitemap' node
const sitemapData = $('Get Sitemap').first();
const xmlText = (sitemapData && sitemapData.json && sitemapData.json.data) ? String(sitemapData.json.data) : "";

// 2. Retrieve the keyword from the 'Isolate Keyword' node
const previousNodeData = $('Isolate Keyword').first();
let targetKeyword = "";

if (previousNodeData && previousNodeData.json && previousNodeData.json.targetKeyword) {
    targetKeyword = previousNodeData.json.targetKeyword;
}

targetKeyword = String(targetKeyword);

// 3. Convert the keyword into a URL slug
const slug = targetKeyword.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');

// 4. Default fallback URL
let articleUrl = "https://theremotesync.com";

// 5. Run the Regex ONLY if the xmlText successfully loaded
if (xmlText) {
    const regex = new RegExp(`<loc>(https:\\/\\/theremotesync\\.com\\/[^<]*${slug}[^<]*)<\\/loc>`, 'i');
    const match = xmlText.match(regex);
    if (match) {
        articleUrl = match[1];
    }
}

// 6. Output both the keyword and the URL for the Gemini node
return [{
    json: {
        targetKeyword: targetKeyword,
        articleUrl: articleUrl
    }
}];
